class Solution {
    public int minChanges(int[] nums, int k) {
        int n = nums.length;
        int[][] dp = new int[n + 1][1 << 10];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j < (1 << 10); j++) {
                dp[i][j] = n;
            }
        }
        dp[0][0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= i; j++) {
                if (i - j + 1 < k) continue;
                int xor = 0;
                for (int l = i - j + 1; l <= i; l++) {
                    xor ^= nums[l - 1];
                }
                if (xor == 0) {
                    dp[i][0] = Math.min(dp[i][0], dp[i - j][0] + (j - 1));
                }
                for (int l = 0; l < (1 << 10); l++) {
                    dp[i][l] = Math.min(dp[i][l], dp[i - j][l ^ xor] + (j - 1));
                }
            }
        }
        return dp[n][0];
    }
}
